import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { getPlanSession, rescheduleMissedTasks } from '../planSession';

const Dashboard = ({ userId }) => {
    const [plan, setPlan] = useState(null);
    const navigate = useNavigate();

    useEffect(() => {
        const fetchAndCheck = async () => {
            const data = await getPlanSession(userId);
            
            // Observe if any past dates were missed
            const today = new Date().setHours(0,0,0,0);
            const missed = data.dailySchedule.some(day => 
                new Date(day.date).getTime() < today && !day.isCompleted
            );

            if (missed) {
                const updated = await rescheduleMissedTasks(data._id);
                setPlan(updated);
            } else {
                setPlan(data);
            }
        };
        fetchAndCheck();
    }, [userId]);

    if (!plan) return <div>Loading...</div>;

    return (
        <div className="dashboard-container">
            {plan.dailySchedule.map((day) => (
                <div key={day._id} className={`day-card ${day.isCompleted ? 'done' : ''}`}>
                    <h4>Day {day.dayNumber} - {new Date(day.date).toLocaleDateString()}</h4>
                    
                    <div className="status-section">
                        {day.isCompleted ? (
                            <span className="status-completed">✅ Completed</span>
                        ) : (
                            <button 
                                className="start-btn" 
                                onClick={() => navigate(`/session/${plan._id}/${day._id}`)}
                            >
                                Click to Start
                            </button>
                        )}
                    </div>
                </div>
            ))}
        </div>
    );
};

export default Dashboard
